import json, re

with open('results/raw_results.json') as f:
    data = json.load(f)

# For each sample, check if the PRIMARY error was fixed
# (regardless of formatting changes)
def extract_key_changes(corrupted, corrected):
    '''Find what changed between corrupted and corrected text.'''
    if corrupted == corrected:
        return []
    # Word-level diff
    cw = corrupted.split()
    gw = corrected.split()
    diffs = []
    for i, (a, b) in enumerate(zip(cw, gw)):
        if a != b:
            diffs.append((a, b))
    return diffs

def semantic_correction_check(sample_id, error_type, gt_corrupted, gt_corrected, llm_corrected):
    '''Check if the primary error type was correctly addressed.'''
    # For correct samples: LLM should say the protocol is fine
    if not gt_corrupted or gt_corrupted == gt_corrected:
        return normalize(llm_corrected) == normalize(gt_corrected)

    # Extract what changed in ground truth
    gt_changes = extract_key_changes(gt_corrupted, gt_corrected)
    if not gt_changes:
        return True

    # Check if LLM made the same change (ignoring extra changes)
    for old_val, new_val in gt_changes:
        old_num = re.findall(r'\d+(?:\.\d+)?', old_val)
        new_num = re.findall(r'\d+(?:\.\d+)?', new_val)
        llm_nums = re.findall(r'\d+(?:\.\d+)?', llm_corrected)

        if old_num and new_num:
            target_num = new_num[0]
            if target_num in llm_corrected:
                return True

    return False

def normalize(t):
    return re.sub(r'\s+', ' ', t.strip().lower())

# Compute semantic accuracy
from collections import defaultdict
by_cond = defaultdict(list)
for r in data:
    by_cond[r['condition']].append(r)

print('=== SEMANTIC CORRECTION ACCURACY ===')
for cond in ['vanilla_llm', 'tool_augmented', 'feedback_loop_1round', 'feedback_loop_3round']:
    items = by_cond[cond]
    sem_correct = []
    for r in items:
        sem = semantic_correction_check(
            r['sample_id'], r['error_type'],
            r['ground_truth_corrupted'], r['ground_truth_corrected'],
            r['llm_corrected_text']
        )
        sem_correct.append(sem)
        if r['error_type'] != 'correct':
            print(f'  {cond} | {r[\"sample_id\"]} ({r[\"error_type\"]}): exact={r[\"is_correction_correct\"]} semantic={sem}')
    print(f'{cond}: semantic_acc={sum(sem_correct)/len(sem_correct):.0%}')
    print()
"
